import{_ as s,o,c as a,ai as l}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"日志","description":"","frontmatter":{"read_when":["更改日志输出或格式","调试 CLI 或 Gateway 网关输出"],"summary":"日志输出界面、文件日志、WS 日志样式和控制台格式化","title":"日志","x-i18n":{"generated_at":"2026-02-03T07:48:14Z","model":"claude-opus-4-5","provider":"pi","source_hash":"efb8eda5e77e3809369a8ff569fac110323a86b3945797093f20e9bc98f39b2e","source_path":"gateway/logging.md","workflow":15}},"headers":[],"relativePath":"zh-CN/gateway/logging.md","filePath":"zh-CN/gateway/logging.md","lastUpdated":null}'),i={name:"zh-CN/gateway/logging.md"};function n(t,e,c,d,r,p){return o(),a("div",null,[...e[0]||(e[0]=[l(`<h1 id="日志" tabindex="-1"><a class="header-anchor" href="#日志">#</a> 日志</h1><p>面向用户的概览（CLI + Control UI + 配置），请参阅 <a href="/docs/logging">/logging</a>。</p><p>OpenSoul 有两个日志&quot;界面&quot;：</p><ul><li><strong>控制台输出</strong>（你在终端 / Debug UI 中看到的内容）。</li><li><strong>文件日志</strong>（JSON 行）由 Gateway 网关日志记录器写入。</li></ul><h2 id="基于文件的日志记录器" tabindex="-1"><a class="header-anchor" href="#基于文件的日志记录器">#</a> 基于文件的日志记录器</h2><ul><li>默认滚动日志文件位于 <code>/tmp/opensoul/</code> 下（每天一个文件）：<code>opensoul-YYYY-MM-DD.log</code><ul><li>日期使用 Gateway 网关主机的本地时区。</li></ul></li><li>日志文件路径和级别可以通过 <code>~/.opensoul/opensoul.json</code> 配置： <ul><li><code>logging.file</code></li><li><code>logging.level</code></li></ul></li></ul><p>文件格式是每行一个 JSON 对象。</p><p>Control UI 的 Logs 标签页通过 Gateway 网关（<code>logs.tail</code>）尾随此文件。CLI 也可以这样做：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --follow</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>Verbose 与日志级别</strong></p><ul><li><strong>文件日志</strong>完全由 <code>logging.level</code> 控制。</li><li><code>--verbose</code> 仅影响<strong>控制台详细程度</strong>（和 WS 日志样式）；它<strong>不会</strong>提高文件日志级别。</li><li>要在文件日志中捕获仅 verbose 的详细信息，请将 <code>logging.level</code> 设置为 <code>debug</code> 或 <code>trace</code>。</li></ul><h2 id="控制台捕获" tabindex="-1"><a class="header-anchor" href="#控制台捕获">#</a> 控制台捕获</h2><p>CLI 捕获 <code>console.log/info/warn/error/debug/trace</code> 并将它们写入文件日志，同时仍打印到 stdout/stderr。</p><p>你可以独立调整控制台详细程度：</p><ul><li><code>logging.consoleLevel</code>（默认 <code>info</code>）</li><li><code>logging.consoleStyle</code>（<code>pretty</code> | <code>compact</code> | <code>json</code>）</li></ul><h2 id="工具摘要脱敏" tabindex="-1"><a class="header-anchor" href="#工具摘要脱敏">#</a> 工具摘要脱敏</h2><p>详细工具摘要（例如 <code>🛠️ Exec: ...</code>）可以在进入控制台流之前屏蔽敏感令牌。这<strong>仅限工具</strong>，不会更改文件日志。</p><ul><li><code>logging.redactSensitive</code>：<code>off</code> | <code>tools</code>（默认：<code>tools</code>）</li><li><code>logging.redactPatterns</code>：正则表达式字符串数组（覆盖默认值） <ul><li>使用原始正则字符串（自动 <code>gi</code>），或如果你需要自定义标志则使用 <code>/pattern/flags</code>。</li><li>匹配项通过保留前 6 个 + 后 4 个字符（长度 &gt;= 18）来屏蔽，否则为 <code>***</code>。</li><li>默认值涵盖常见的键赋值、CLI 标志、JSON 字段、bearer 头、PEM 块和流行的令牌前缀。</li></ul></li></ul><h2 id="gateway-网关-websocket-日志" tabindex="-1"><a class="header-anchor" href="#gateway-网关-websocket-日志">#</a> Gateway 网关 WebSocket 日志</h2><p>Gateway 网关以两种模式打印 WebSocket 协议日志：</p><ul><li><strong>普通模式（无 <code>--verbose</code>）</strong>：仅打印&quot;有趣的&quot;RPC 结果： <ul><li>错误（<code>ok=false</code>）</li><li>慢调用（默认阈值：<code>&gt;= 50ms</code>）</li><li>解析错误</li></ul></li><li><strong>详细模式（<code>--verbose</code>）</strong>：打印所有 WS 请求/响应流量。</li></ul><h3 id="ws-日志样式" tabindex="-1"><a class="header-anchor" href="#ws-日志样式">#</a> WS 日志样式</h3><p><code>opensoul gateway</code> 支持每个 Gateway 网关的样式切换：</p><ul><li><code>--ws-log auto</code>（默认）：普通模式已优化；详细模式使用紧凑输出</li><li><code>--ws-log compact</code>：详细时使用紧凑输出（配对的请求/响应）</li><li><code>--ws-log full</code>：详细时使用完整的每帧输出</li><li><code>--compact</code>：<code>--ws-log compact</code> 的别名</li></ul><p>示例：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 优化的（仅错误/慢调用）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 显示所有 WS 流量（配对）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ws-log</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compact</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 显示所有 WS 流量（完整元数据）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ws-log</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> full</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="控制台格式化-子系统日志" tabindex="-1"><a class="header-anchor" href="#控制台格式化-子系统日志">#</a> 控制台格式化（子系统日志）</h2><p>控制台格式化器是 <strong>TTY 感知的</strong>，打印一致的带前缀行。子系统日志记录器保持输出分组且易于扫描。</p><p>行为：</p><ul><li>每行都有<strong>子系统前缀</strong>（例如 <code>[gateway]</code>、<code>[canvas]</code>、<code>[tailscale]</code>）</li><li><strong>子系统颜色</strong>（每个子系统稳定）加上级别着色</li><li><strong>当输出是 TTY 或环境看起来像富终端时着色</strong>（<code>TERM</code>/<code>COLORTERM</code>/<code>TERM_PROGRAM</code>），遵守 <code>NO_COLOR</code></li><li><strong>缩短的子系统前缀</strong>：删除前导 <code>gateway/</code> + <code>channels/</code>，保留最后 2 个段（例如 <code>whatsapp/outbound</code>）</li><li><strong>按子系统的子日志记录器</strong>（自动前缀 + 结构化字段 <code>{ subsystem }</code>）</li><li><strong><code>logRaw()</code></strong> 用于 QR/UX 输出（无前缀，无格式化）</li><li><strong>控制台样式</strong>（例如 <code>pretty | compact | json</code>）</li><li><strong>控制台日志级别</strong>与文件日志级别分开（当 <code>logging.level</code> 设置为 <code>debug</code>/<code>trace</code> 时，文件保留完整详情）</li><li><strong>WhatsApp 消息正文</strong>以 <code>debug</code> 级别记录（使用 <code>--verbose</code> 查看它们）</li></ul><p>这保持现有文件日志稳定，同时使交互式输出易于扫描。</p>`,31)])])}const u=s(i,[["render",n]]);export{h as __pageData,u as default};
